from typing import TypeVar, Optional, List, Dict, Union, Generic

T = TypeVar('T')
K = TypeVar('K')
V = TypeVar('V')

class Repository(Generic[T]):
    def __init__(self, items: List[T]) -> None:
        self._items = items

    def find(self, predicate) -> Optional[T]:
        for item in self._items:
            if predicate(item):
                return item
        return None

    def find_all(self, predicate) -> List[T]:
        return [item for item in self._items if predicate(item)]

def merge_dicts(a: Dict[K, V], b: Dict[K, V]) -> Dict[K, V]:
    result: Dict[K, V] = {}
    result.update(a)
    result.update(b)
    return result

def process_value(value: Union[str, int, None]) -> str:
    if value is None:
        return 'empty'
    return str(value)
